import java.io.File;
import java.io.FileInputStream;
import java.io.IOException;

public class FileLoader {

    private static final String BASE_PATH = "/path/to/files/";

    public void loadFile(String fileName) {
        try {
            String sanitizedFileName = fileName.replaceAll("\\.\\.", "");
            File file = new File(BASE_PATH + sanitizedFileName);

            if (file.getCanonicalPath().startsWith(BASE_PATH)) {
                FileInputStream fis = new FileInputStream(file);

                // Read file content
                // Do something with the content

                fis.close();
            } else {
                System.out.println("Access denied. Invalid file path.");
            }
        } catch (IOException e) {
            System.out.println("Error loading file: " + e.getMessage());
        }
    }

    public static void main(String[] args) {
        FileLoader loader = new FileLoader();
        String userInput = "../secretfile.txt";

        loader.loadFile(userInput);
    }
}

